-- Secure Logging and Auditing Migration\n-- Enforce HTTPS is usually handled at the gateway/infrastructure level in Supabase (Cloud),\n-- but we can add policies and logs to detect unusual patterns.\n\n-- 1. Create a dedicated security_audit_logs table\nCREATE TABLE IF NOT EXISTS public.security_audit_logs (\n    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,\n    event_type TEXT NOT NULL, -- auth_attempt, api_error, rate_limit_hit, suspicious_activity\n    severity TEXT CHECK (severity IN ('info', 'warning', 'critical')) DEFAULT 'info',\n    component TEXT,\n    metadata JSONB DEFAULT '{}'::jsonb,\n    ip_address TEXT,\n    user_agent TEXT,\n    created_at TIMESTAMPTZ DEFAULT now()\n);\n\n-- 2. Enable RLS (Service role only for writes, internal access only)\nALTER TABLE public.security_audit_logs ENABLE ROW LEVEL SECURITY;\n\n-- Be explicit: no public policies. Service role bypasses RLS.\n\n-- 3. Trigger for Auth Attempts (detecting brute force)\n-- While auth.users is in a different schema, we can log from our application logic.\n-- However, we can track 'last_sign_in_at' or similar patterns if we have a profile trigger.\n\n-- 4. Create a function to log security events (Security Definer)\nCREATE OR REPLACE FUNCTION public.log_security_event(\n    p_event_type TEXT,\n    p_severity TEXT,\n    p_component TEXT,\n    p_metadata JSONB DEFAULT '{}'::jsonb\n)\nRETURNS VOID\nLANGUAGE plpgsql\nSECURITY DEFINER\nAS c:\Users\shaik\Downloads\foliogen\nBEGIN\n    INSERT INTO public.security_audit_logs (\n        user_id,\n        event_type,\n        severity,\n        component,\n        metadata,\n        ip_address\n    )\n    VALUES (\n        auth.uid(),\n        p_event_type,\n        p_severity,\n        p_component,\n        p_metadata,\n        current_setting('request.headers', true)::jsonb->>'x-forwarded-for'\n    );\nEND;\nc:\Users\shaik\Downloads\foliogen;\n\n-- 5. Track unusual traffic patterns (example: high error rate per IP)\n-- We can create a view or periodic job to analyze error_logs and security_audit_logs.\n\n-- 6. Restriction on public internet access:\n-- In Supabase, this is controlled via the dashboard (IP Allow-listing).\n-- We can add a policy to restrict access to sensitive tables during maintenance if needed.\n